from typing import List

class Solution:
    def splitWordsBySeparator(self, words: List[str], separator: str) -> List[str]:
        result = []
        for w in words:
            parts = w.split(separator)
            for p in parts:
                if p != "":
                    result.append(p)
        return result
```

